// --- THE COSMIC SHADER (Versione ULTRA - Alta Luminosità) ---

void mainImage(out vec4 fragColor, in vec2 fragCoord) {
    // TEMPO
    float t = iTime * 0.5;

    // COORDINATE
    vec2 st = (fragCoord - 0.5 * iResolution.xy) / iResolution.y;
    vec2 u_cloud = st * 2.0;

    // =========================================================
    // 1. NUBI VOLUMETRICHE (Alta Qualità: 60 step)
    // =========================================================
    vec4 o = vec4(0.0);
    float s = 0.0;
    vec3 p = vec3(0.0);

    for(int it = 0; it < 60; it++) { 
        p += vec3(u_cloud * s, s);
        s = 6.0 + p.y;

        s -= abs(dot(sin(t + 0.1 * p.z + 0.3 * p / 0.08), vec3(0.16)));
        s -= abs(dot(sin(t + 0.1 * p.z + 0.3 * p / 0.20), vec3(0.40)));
        s -= abs(dot(sin(t + 0.1 * p.z + 0.3 * p / 0.60), vec3(1.20)));

        s = 0.1 + abs(s) * 0.2;
        // Moltiplicatore luce nuvole aumentato (da 4.0 a 6.0)
        o += vec4(6.0, 3.0, 1.5, 0.0) / s; 
    }
    o *= smoothstep(0.8, 0.75, abs(u_cloud.y));

    // =========================================================
    // 2. NEBULA (Kali-Set Fractal - Alta Qualità: 15 step)
    // =========================================================
    vec4 o2 = vec4(0.0);
    float t2 = -t * 0.05;
    float k = 0.0;

    for(int it = 0; it < 15; it++) { 
        float d_neb = fract(k - 3.0 * t2);
        vec4 c = vec4(st * d_neb, k, 0.0) * 28.0;

        for(int j = 0; j < 22; j++) {
            float dotC = dot(c, c);
            if(dotC < 0.001) dotC = 0.001; 
            vec4 temp = abs(c / dotC - vec4(7.0 - 0.2 * sin(t2), 6.3, 0.7, 1.0 - cos(t2 / 0.8)) / 7.0);
            c = temp.xzyw;
        }

        float mult_d = d_neb * d_neb;
        o2 -= c * c.yzww * mult_d / vec4(3.0, 5.0, 1.0, 1.0);
        k -= 0.06;
    }
    o += o2;

    float lenU = length(u_cloud);
    if(lenU < 0.001) lenU = 0.001;

    // Compressione luce più morbida per far passare più luminosità
    vec4 val = o / 1000.0 / lenU; 
    o = val / (0.8 + abs(val)); 

    // =========================================================
    // 3. CAMPO STELLARE (Stelle più brillanti)
    // =========================================================
    vec3 col = vec3(0.0);
    float t_star = 0.0; 

    for(int idx = 0; idx < 8; idx++) {
        float j = float(idx) / 8.0;
        float depth = fract(j + t_star);
        float scale = mix(20.0, 0.5, depth);
        float fade = depth * smoothstep(1.0, 0.9, depth);

        vec2 luv = st * scale + j * 453.2 - t * 0.05;

        vec3 layerCol = vec3(0.0);
        vec2 gv = fract(luv);
        vec2 id = floor(luv);

        for(int y = -1; y <= 1; y++) {
            for(int x = -1; x <= 1; x++) {
                vec2 offs = vec2(float(x), float(y));

                vec2 hp = fract((id + offs) * vec2(0.129898, 0.78233));
                hp += dot(hp, hp + 19.19);
                float n = fract(hp.x * hp.y);
                float size = fract(n);

                vec2 suv = gv - offs - vec2(n, fract(n * 34.0)) + 0.5;
                // Stelle più grandi e luminose
                float flare = smoothstep(0.1, 0.9, size) * 0.8; 

                float d_star = length(suv);
                if(d_star < 0.001) d_star = 0.001; 
                float m = sin(0.025 * 1.2) / d_star; 
                float rays = max(0.0, 0.5 - abs(suv.x * suv.y * 1000.0));
                m += (rays * flare) * 2.0;
                m *= smoothstep(1.0, 0.1, d_star);

                vec3 color = sin(vec3(0.2, 0.3, 0.9) * fract(n * 23.2) * 6.28318) * 0.25 + 0.75;
                color = color * vec3(0.9, 0.59, 0.9 + size);

                float star_val = m * (sin(t * 0.6 + n * 6.28318) * 0.5 + 0.5);
                layerCol += star_val * size * color;
            }
        }
        col += layerCol * fade;
    }

    float starMask = smoothstep(-0.4, 0.1, u_cloud.y);
    o.rgb += col * starMask * o2.xyz * 15.0; // Nebulosa di fondo intensificata

    // =========================================================
    // 4. CORREZIONE LUMINOSITÀ FINALE E CONTRASTO
    // =========================================================
    vec3 finalColor = o.rgb * 1.8; // <-- AUMENTA QUESTO VALORE PER AVERE PIÙ LUCE (es. 2.0 o 2.5)

    // Aggiungiamo un pizzico di contrasto
    finalColor = smoothstep(0.0, 1.0, finalColor);

    fragColor = vec4(clamp(finalColor, 0.0, 1.0), 1.0);
}
